SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT cg.CODE_GROUP_ID AS codeGroupId, cg.CODE_GROUP_NAME AS codeGroupName, cg.CODE_GROUP_DESC AS codeGroupDesc, cg.LAST_UPDATE_DTIME AS lastUpdateDtime, cg.LAST_UPDATE_USER_ID AS lastUpdateUserId, cg.BIZ_GROUP_ID AS bizGroupId, (SELECT COUNT(*) FROM FWK_CODE c WHERE c.CODE_GROUP_ID = cg.CODE_GROUP_ID) AS codeCount FROM FWK_CODE_GROUP cg
ORDER BY cg.CODE_GROUP_ID ORDER BY cg.CODE_GROUP_NAME ORDER BY codeCount ORDER BY cg.CODE_GROUP_DESC ORDER BY cg.CODE_GROUP_ID
DESC ASC
ORDER BY cg.CODE_GROUP_ID
) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
